import {
	IInsightFacade,
	InsightDataset,
	InsightDatasetKind,
	InsightResult,
	InsightError,
	NotFoundError,
	ResultTooLargeError,
} from "./IInsightFacade";
import { Section } from "./Section";
import { Room } from "./Room";
import * as fs from "fs-extra";

import { QueryValidator } from "./QueryValidator";
import { DatasetValidator } from "./DatasetValidator";
import { QueryProcessor } from "./QueryProcessor";

interface PersistedDataset {
	id: string;
	kind: InsightDatasetKind;
	data: Section[] | Room[];
}

export default class InsightFacade implements IInsightFacade {
	private static readonly MAX_RESULTS = 5000;
	private static readonly JSON_EXTENSION_LENGTH = 5;

	private readonly persistDir: string = "./data";
	private queryValidator = new QueryValidator();
	private datasetValidator = new DatasetValidator();
	private queryProcessor = new QueryProcessor();
	private datasets = new Map<string, Section[] | Room[]>();
	private datasetKinds = new Map<string, InsightDatasetKind>();
	private loadPromise: Promise<void>;

	constructor() {
		this.loadPromise = this.loadPersistedDatasets();
	}

	public async addDataset(id: string, content: string, kind: InsightDatasetKind): Promise<string[]> {
		await this.loadPromise;
		this.validateAddDatasetInput(id, kind);
		const dataset = await this.extractDataset(content, kind);
		this.addToMemory(id, dataset, kind);
		await this.persistDataset(id, dataset, kind);
		return Array.from(this.datasets.keys());
	}

	private validateAddDatasetInput(id: string, kind: InsightDatasetKind): void {
		this.datasetValidator.validateId(id);
		if (this.datasets.has(id)) {
			throw new InsightError(`Dataset with id '${id}' already exists`);
		}
		if (kind !== InsightDatasetKind.Sections && kind !== InsightDatasetKind.Rooms) {
			throw new InsightError("Unsupported dataset kind");
		}
	}

	private async extractDataset(content: string, kind: InsightDatasetKind): Promise<Section[] | Room[]> {
		if (kind === InsightDatasetKind.Sections) {
			const sections = await this.datasetValidator.extractSectionsFromZip(content);
			if (sections.length === 0) {
				throw new InsightError("No valid sections found in dataset");
			}
			return sections;
		} else {
			try {
				const rooms = await this.datasetValidator.extractRoomsFromZip(content);
				if (rooms.length === 0) {
					throw new InsightError("No valid rooms found in dataset");
				}
				return rooms;
			} catch (error) {
				if (error instanceof InsightError) {
					throw error;
				}
				throw new InsightError(`Failed to extract rooms: ${error}`);
			}
		}
	}

	private addToMemory(id: string, dataset: Section[] | Room[], kind: InsightDatasetKind): void {
		this.datasets.set(id, dataset);
		this.datasetKinds.set(id, kind);
	}

	private async persistDataset(id: string, dataset: Section[] | Room[], kind: InsightDatasetKind): Promise<void> {
		try {
			await this.saveToDisk(id, dataset, kind);
		} catch (error) {
			this.datasets.delete(id);
			this.datasetKinds.delete(id);
			throw new InsightError(`Failed to persist dataset: ${error}`);
		}
	}

	private async saveToDisk(id: string, dataset: Section[] | Room[], kind: InsightDatasetKind): Promise<void> {
		try {
			await fs.ensureDir(this.persistDir);
			const filepath = `${this.persistDir}/${id}.json`;
			const persistedData: PersistedDataset = {
				id,
				kind,
				data: dataset,
			};
			await fs.writeJSON(filepath, persistedData, { spaces: 2 });
		} catch (error) {
			throw new InsightError(`Failed to save dataset to disk: ${error}`);
		}
	}

	private async loadPersistedDatasets(): Promise<void> {
		this.datasets = new Map<string, Section[] | Room[]>();
		this.datasetKinds = new Map<string, InsightDatasetKind>();

		try {
			const exists = await fs.pathExists(this.persistDir);
			if (!exists) {
				return;
			}
			const files = await fs.readdir(this.persistDir);

			const loadPromises = files
				.filter((file) => file.endsWith(".json"))
				.map(async (file) => {
					try {
						const filepath = `${this.persistDir}/${file}`;
						const persistedData: PersistedDataset = await fs.readJSON(filepath);

						return {
							id: persistedData.id,
							kind: persistedData.kind,
							data: persistedData.data,
						};
					} catch {
						return null;
					}
				});

			const results = await Promise.all(loadPromises);

			for (const result of results) {
				if (result !== null) {
					this.datasets.set(result.id, result.data);
					this.datasetKinds.set(result.id, result.kind);
				}
			}
		} catch {
			// Start with empty datasets - maps already initialized above
		}
	}

	public async removeDataset(id: string): Promise<string> {
		await this.loadPromise;

		this.datasetValidator.validateId(id);

		if (!this.datasets.has(id)) {
			throw new NotFoundError(`Dataset with id '${id}' not found`);
		}

		try {
			const filepath = `${this.persistDir}/${id}.json`;
			await fs.remove(filepath);
		} catch (error) {
			throw new InsightError(`Failed to remove dataset from disk: ${error}`);
		}

		this.datasets.delete(id);
		this.datasetKinds.delete(id);
		return id;
	}

	public async listDatasets(): Promise<InsightDataset[]> {
		await this.loadPromise;

		const result: InsightDataset[] = [];

		for (const [id, dataset] of this.datasets.entries()) {
			const kind = this.datasetKinds.get(id)!;
			result.push({
				id: id,
				kind: kind,
				numRows: dataset.length,
			});
		}
		return result;
	}

	public async performQuery(query: unknown): Promise<InsightResult[]> {
		if (!query || typeof query !== "object" || Array.isArray(query)) {
			throw new InsightError("Query must be an object");
		}

		const q = query as Record<string, any>;
		this.queryValidator.validateQueryStructure(q);

		const datasetId = this.extractDatasetId(q);
		if (!datasetId) {
			throw new InsightError("Query must reference exactly one dataset");
		}

		await this.loadPromise;
		const dataset = this.datasets.get(datasetId);
		if (!dataset) {
			throw new InsightError(`Dataset ${datasetId} not found`);
		}

		const filtered = this.applyWhere(dataset, q.WHERE);

		// Check size limit before transformations (transformations typically reduce size)
		if (!q.TRANSFORMATIONS && filtered.length > InsightFacade.MAX_RESULTS) {
			throw new ResultTooLargeError("Query result exceeds 5000 rows");
		}

		let results: InsightResult[];
		if (q.TRANSFORMATIONS) {
			results = this.queryProcessor.applyTransformations(filtered, q.TRANSFORMATIONS);
			results = this.selectColumns(results, q.OPTIONS.COLUMNS);
		} else {
			results = this.applyOptions(filtered, q.OPTIONS);
		}

		// Final size check after transformations (just in case)
		if (results.length > InsightFacade.MAX_RESULTS) {
			throw new ResultTooLargeError("Query result exceeds 5000 rows");
		}

		if (q.OPTIONS.ORDER) {
			results = this.queryProcessor.applySorting(results, q.OPTIONS.ORDER);
		}

		return results;
	}

	private extractDatasetId(query: Record<string, any>): string | null {
		const keys = new Set<string>();
		this.collectKeys(query, keys);
		const ids = [
			...new Set(
				Array.from(keys)
					.map((k) => k.split("_")[0])
					.filter(Boolean)
			),
		];
		return ids.length === 1 ? ids[0] : null;
	}

	private collectKeys(obj: any, keys: Set<string>): void {
		if (typeof obj === "string" && obj.includes("_")) {
			keys.add(obj);
		} else if (Array.isArray(obj)) {
			obj.forEach((item) => this.collectKeys(item, keys));
		} else if (obj && typeof obj === "object") {
			Object.values(obj).forEach((value) => this.collectKeys(value, keys));
		}
	}

	private applyWhere(dataset: Section[] | Room[], where: any): (Section | Room)[] {
		if (!where || Object.keys(where).length === 0) return dataset;
		return dataset.filter((item) => this.evaluateFilter(item, where));
	}

	private evaluateFilter(item: Section | Room, filter: any): boolean {
		// fixed this from AI's version - EK. No defensive programming and masking of bugs.
		if (!filter || typeof filter !== "object") throw new InsightError("Invalid filter");

		const [key, value] = Object.entries(filter)[0];
		switch (key) {
			case "AND":
				return Array.isArray(value) && value.every((f) => this.evaluateFilter(item, f));
			case "OR":
				return Array.isArray(value) && value.some((f) => this.evaluateFilter(item, f));
			case "NOT":
				return !this.evaluateFilter(item, value);
			case "LT":
				return this.evaluateComparison(item, value, (a, b) => a < b);
			case "GT":
				return this.evaluateComparison(item, value, (a, b) => a > b);
			case "EQ":
				return this.evaluateComparison(item, value, (a, b) => a === b);
			case "IS":
				return this.evaluateStringComparison(item, value);
			default:
				return false;
		}
	}

	private evaluateComparison(item: Section | Room, comparison: any, op: (a: number, b: number) => boolean): boolean {
		const [fieldKey, expectedValue] = Object.entries(comparison)[0];
		const field = fieldKey.split("_")[1];
		const value = (item as any)[field];
		return typeof value === "number" && op(value, expectedValue as number);
	}

	private evaluateStringComparison(item: Section | Room, comparison: any): boolean {
		const [fieldKey, pattern] = Object.entries(comparison)[0];
		const field = fieldKey.split("_")[1];
		const value = (item as any)[field];
		if (typeof value !== "string" || typeof pattern !== "string") return false;

		const startWild = pattern.startsWith("*");
		const endWild = pattern.endsWith("*");
		const cleanPattern = pattern.replace(/^\*|\*$/g, "");

		if (startWild && endWild) return value.includes(cleanPattern);
		if (startWild) return value.endsWith(cleanPattern);
		if (endWild) return value.startsWith(cleanPattern);
		return value === cleanPattern;
	}

	private applyOptions(items: (Section | Room)[], options: any): InsightResult[] {
		return items.map((item) => {
			const result: InsightResult = {};
			options.COLUMNS.forEach((col: string) => {
				const field = col.split("_")[1];
				result[col] = (item as any)[field];
			});
			return result;
		});
	}

	private selectColumns(results: InsightResult[], columns: string[]): InsightResult[] {
		return results.map((result) => {
			const selected: InsightResult = {};
			columns.forEach((col) => {
				selected[col] = result[col];
			});
			return selected;
		});
	}
}
